  // ===== FAQ =====
  "faq.h2": { fr: "FAQ", en: "FAQ" },
  "faq.p":  { fr: "Toutes vos questions sur nos programmes de tutorat TEF & TCF Canada.", en: "All your questions about our TEF Canada and TCF Canada tutoring programs." },
  "faq.q1": { fr: "Quelle différence entre le TEF Canada et le TCF Canada ?", en: "What is the difference between TEF Canada and TCF Canada?" },
  "faq.a1": {
    fr: "Le <strong>TEF Canada</strong> est organisé par la CCIP (CCI Paris). Le <strong>TCF Canada</strong> est organisé par France Éducation international. Les deux sont reconnus par IRCC. Le choix dépend de la disponibilité dans votre pays et de votre profil.",
    en: "<strong>TEF Canada</strong> is organized by the CCIP (CCI Paris). <strong>TCF Canada</strong> is organized by France Éducation international. Both are recognized by IRCC. The choice depends on availability in your country and your profile."
  },
  "faq.q2": { fr: "Combien de temps faut-il pour se préparer ?", en: "How long does preparation take?" },
  "faq.a2": {
    fr: "En général, comptez <strong>4 à 12 semaines</strong> selon votre niveau de départ, à raison de 1 à 2 heures par jour.",
    en: "Generally, plan for <strong>4 to 12 weeks</strong> depending on your starting level, at 1 to 2 hours per day."
  },
  "faq.q3": { fr: "Le programme de tutorat est-il entièrement en ligne ?", en: "Is the tutoring program fully online?" },
  "faq.a3": {
    fr: "Oui, tous nos programmes de tutorat sont <strong>100% en ligne</strong>, accessibles 24h/24 depuis un ordinateur, une tablette ou un smartphone.",
    en: "Yes, all our tutoring programs are <strong>100% online</strong>, accessible 24/7 from a computer, tablet or smartphone."
  },
  "faq.q4": { fr: "Est-ce que je peux passer des tests interactifs ?", en: "Can I take interactive tests?" },
  "faq.a4": {
    fr: "Oui ! Quiz, compréhension orale &amp; écrite, simulations avec résultats automatiques et correction immédiate.",
    en: "Yes! Quizzes, listening &amp; reading comprehension, simulations with automatic results and immediate correction."
  },
  "faq.q5": { fr: "Est-ce que j'aurai un espace membre privé ?", en: "Will I have a private member space?" },
  "faq.a5": {
    fr: "Oui. Chaque étudiant dispose d'un <strong>espace membre sécurisé</strong> avec tableau de bord, progression, scores et certificat ARCADINS.",
    en: "Yes. Every student gets a <strong>secure member space</strong> with dashboard, progress tracking, scores and ARCADINS certificate."
  },
  "faq.q6": { fr: "Ce programme garantit-il l'obtention d'un visa ?", en: "Does this program guarantee a visa?" },
  "faq.a6": {
    fr: "<strong>Non.</strong> ARCADINS Training Center prépare uniquement au test linguistique et ne garantit pas l'obtention d'un visa ou d'un résultat officiel.",
    en: "<strong>No.</strong> ARCADINS Training Center only prepares for the language test and does not guarantee obtaining a visa or an official result."
  },
  "faq.q7": { fr: "Combien de temps mon accès est-il valide ?", en: "How long is my access valid?" },
  "faq.a7": {
    fr: "L'accès est valide <strong>6 mois</strong> à partir de l'activation de votre compte.",
    en: "Access is valid for <strong>6 months</strong> from the activation of your account."
  },

  // ===== MENTION LÉGALE =====
  "legal.note": { fr: "⚠️ Note légale importante :", en: "⚠️ Important legal notice:" },
  "legal.text": {
    fr: "ARCADINS Training Center est une plateforme de tutorat et de préparation linguistique. Elle n'est pas un organisme gouvernemental, ne remplace pas IRCC, MIFI ou les centres officiels TEF/TCF, et ne garantit pas l'obtention d'un visa ou d'un résultat officiel.",
    en: "ARCADINS Training Center is a language tutoring and preparation platform. It is not a government agency, does not replace IRCC, MIFI or official TEF/TCF centers, and does not guarantee obtaining a visa or official result."
  },

