  "testi.1.result": { fr: "✅ NCLC 9 – Express Entry validé", en: "✅ NCLC 9 – Express Entry approved" },

  "testi.2.text":   { fr: "« J'avais peur de l'épreuve d'expression orale. Les exercices avec minuterie et les conseils de structuration du discours m'ont aidée à dépasser cette peur. J'ai obtenu NCLC 8 et mon dossier Express Entry est en cours ! »", en: "« I was afraid of the oral expression test. The timed exercises and speech structuring tips helped me overcome that fear. I scored NCLC 8 and my Express Entry application is underway! »" },
  "testi.2.meta":   { fr: "Casablanca, Maroc", en: "Casablanca, Morocco" },
  "testi.2.result": { fr: "✅ NCLC 8 – Résidence permanente en cours", en: "✅ NCLC 8 – Permanent residence in progress" },

  "testi.3.text":   { fr: "« La plateforme est très bien faite. Le test de niveau initial m'a donné une vision claire de mes points faibles. En 8 semaines d'accompagnement intensif avec les modules ARCADINS, j'ai obtenu NCLC 7 partout au TCF Canada. »", en: "« The platform is very well built. The initial level test gave me a clear picture of my weak points. In 8 weeks of intensive coaching with ARCADINS modules, I scored NCLC 7 across the board at TCF Canada. »" },
  "testi.3.meta":   { fr: "Douala, Cameroun", en: "Douala, Cameroon" },
  "testi.3.result": { fr: "✅ NCLC 7 – PEQ Québec soumis", en: "✅ NCLC 7 – PEQ Quebec submitted" },

  "testi.4.text":   { fr: "« Le plan VIP avec coaching a transformé mon expression orale. Mon formateur m'a donné des retours précis sur ma prononciation et ma structure. J'ai progressé de NCLC 5 à NCLC 8 en 10 semaines. Merci ARCADINS ! »", en: "« The VIP plan with coaching transformed my oral expression. My trainer gave me precise feedback on my pronunciation and structure. I went from NCLC 5 to NCLC 8 in 10 weeks. Thank you ARCADINS! »" },
  "testi.4.meta":   { fr: "Tunis, Tunisie", en: "Tunis, Tunisia" },
