  "tef.what.tag":   { fr: "Présentation",                      en: "Overview" },
  "tef.what.h2":    { fr: "Qu'est-ce que le TEF Canada ?",     en: "What is TEF Canada?" },
  "tef.what.p1":    { fr: "Le <strong>TEF Canada</strong> (Test d'Évaluation de Français Canada) est un test linguistique officiel organisé par la Chambre de Commerce et d'Industrie de Paris (CCIP). Il est reconnu par <strong>Immigration, Réfugiés et Citoyenneté Canada (IRCC)</strong> pour évaluer les compétences en français des candidats à l'immigration.", en: "The <strong>TEF Canada</strong> (French Evaluation Test for Canada) is an official language test organized by the Paris Chamber of Commerce and Industry (CCIP). It is recognized by <strong>Immigration, Refugees and Citizenship Canada (IRCC)</strong> to assess the French skills of immigration candidates." },
  "tef.what.p2":    { fr: "Les résultats sont valides <strong>2 ans</strong> et convertis en niveaux NCLC (Niveaux de compétence linguistique canadiens), qui déterminent votre pointage dans le cadre d'Express Entry et d'autres programmes.", en: "Results are valid for <strong>2 years</strong> and converted into NCLC levels (Canadian Language Benchmarks), which determine your score under Express Entry and other programs." },
  "tef.usedfor":    { fr: "🎯 Utilisé pour :",                en: "🎯 Used for:" },
  "tef.use1":       { fr: "✅ Express Entry – Entrée Express", en: "✅ Express Entry" },
  "tef.use2":       { fr: "✅ Résidence permanente au Canada", en: "✅ Permanent residence in Canada" },
  "tef.use3":       { fr: "✅ Programme des Travailleurs Qualifiés", en: "✅ Skilled Worker Program" },
  "tef.use4":       { fr: "✅ Études au Canada (universités francophones)", en: "✅ Studies in Canada (French universities)" },
  "tef.use5":       { fr: "✅ Citoyenneté canadienne",         en: "✅ Canadian citizenship" },
  "tef.struct.h":   { fr: "📊 Structure du TEF Canada",       en: "📊 TEF Canada Structure" },
  "tef.mod.tag":    { fr: "Notre formation",                   en: "Our program" },
  "tef.mod.h2":     { fr: "Modules de préparation TEF Canada", en: "TEF Canada preparation modules" },
  "tef.mod.p":      { fr: "Un parcours complet pour chaque composante du test.", en: "A complete program for each component of the test." },
  "tef.nclc.tag":   { fr: "Barème NCLC",                      en: "NCLC scale" },
  "tef.nclc.h2":    { fr: "Comprendre les niveaux NCLC pour Express Entry", en: "Understanding NCLC levels for Express Entry" },
  "tef.nclc.p":     { fr: "Chaque compétence du TEF Canada est convertie en niveau NCLC. Voici les seuils clés pour l'immigration.", en: "Each TEF Canada skill is converted into an NCLC level. Here are the key thresholds for immigration." },
  "tef.nclc.note":  { fr: "* Barèmes indicatifs — consultez le site officiel du TEF Canada pour les données actualisées.", en: "* Indicative scales — consult the official TEF Canada website for updated data." },
