  // ===== GUIDE D'UTILISATION =====
  "guide.tag":    { fr: "📚 Guide complet", en: "📚 Complete Guide" },
  "guide.h1":     { fr: "Comment utiliser la plateforme ARCADINS ?", en: "How to use the ARCADINS platform?" },
  "guide.p":      { fr: "Suivez ces 8 étapes simples pour passer de l'inscription à votre certificat officiel. Tout est expliqué, rien n'est compliqué.", en: "Follow these 8 simple steps from registration to your official certificate. Everything is explained, nothing is complicated." },
  "guide.btn1":   { fr: "✏️ Commencer maintenant", en: "✏️ Start Now" },
  "guide.btn2":   { fr: "Voir les plans →", en: "View Plans →" },

  "guide.path.tag":  { fr: "Votre parcours", en: "Your Journey" },
  "guide.path.h2":   { fr: "De l'inscription au certificat en 8 étapes", en: "From registration to certificate in 8 steps" },
  "guide.step.lbl1": { fr: "Inscription", en: "Registration" },
  "guide.step.lbl2": { fr: "Test de niveau", en: "Level Test" },
  "guide.step.lbl3": { fr: "Choisir un plan", en: "Choose a Plan" },
  "guide.step.lbl4": { fr: "Paiement", en: "Payment" },
  "guide.step.lbl5": { fr: "Qualification", en: "Qualification" },
  "guide.step.lbl6": { fr: "14 Modules", en: "14 Modules" },
  "guide.step.lbl7": { fr: "Test final", en: "Final Test" },
  "guide.step.lbl8": { fr: "Certificat 🎓", en: "Certificate 🎓" },

  "guide.steps.h2": { fr: "Les 8 étapes expliquées", en: "The 8 steps explained" },
  "guide.steps.p":  { fr: "Chaque étape est conçue pour vous préparer progressivement au TEF ou TCF Canada.", en: "Each step is designed to progressively prepare you for the TEF or TCF Canada." },

  "guide.s1.h":    { fr: "📝 Créez votre compte gratuitement", en: "📝 Create your account for free" },
  "guide.s1.p1":   { fr: "Remplissez le formulaire d'inscription sur la page d'accueil : votre nom, email, téléphone, pays, objectif (TEF ou TCF Canada) et niveau actuel. C'est gratuit et prend moins de 2 minutes.", en: "Fill in the registration form on the homepage: your name, email, phone, country, goal (TEF or TCF Canada) and current level. It's free and takes less than 2 minutes." },
  "guide.s1.p2":   { fr: "Après l'inscription, vous recevez un <strong>email de confirmation</strong> avec vos identifiants d'accès. Vérifiez votre dossier spam si vous ne le voyez pas.", en: "After registration, you receive a <strong>confirmation email</strong> with your access credentials. Check your spam folder if you don't see it." },
