// ============================================================
// MOTEUR DE TRADUCTION
// ============================================================
let currentLang = localStorage.getItem('arc_lang') || 'fr';

function t(key) {
  const entry = translations[key];
  if (!entry) return key;
  return entry[currentLang] || entry['fr'] || key;
}

function applyTranslations() {
  const L = currentLang;

  // --- Éléments data-i18n standard ---
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    const entry = translations[key];
    if (!entry) return;
    const val = entry[L] || entry['fr'];
    if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
      el.placeholder = val;
    } else {
      el.innerHTML = val;
    }
  });

  // --- Placeholders via data-i18n-placeholder ---
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    const key = el.getAttribute('data-i18n-placeholder');
    const entry = translations[key];
    if (!entry) return;
    el.placeholder = entry[L] || entry['fr'];
  });

  // --- Restaurer l'année dans le footer (innerHTML écrase le span) ---
  const footerYear = document.getElementById('footerYear');
  if (footerYear) footerYear.textContent = new Date().getFullYear();

  // --- Langue HTML ---
  document.documentElement.lang = L;

  // --- Bouton de langue ---
  const btn = document.getElementById('langToggle');
  if (btn) btn.textContent = L === 'fr' ? '🇬🇧 EN' : '🇫🇷 FR';

  // --- BARRE DE NOTIFICATION ---
  const notifBar = document.getElementById('notifBar');
  if (notifBar) {
    const isPages = window.location.pathname.includes('/pages/');
    const inscLink = isPages ? '../index.html#inscription' : '#inscription';
    notifBar.innerHTML = `
      <span class="notif-bar-count">${t('notif.badge')}</span>
      ${t('notif.text')}
      <a href="${inscLink}">${t('notif.cta')}</a>
      <button class="notif-bar-close" onclick="closeNotifBar()">✕</button>`;
  }

  // --- CHAT WIDGET ---
  const chatOnlineStatus = document.getElementById('chatOnlineStatus');
  if (chatOnlineStatus) chatOnlineStatus.textContent = t('chat.online');
  const chatAgentName = document.getElementById('chatAgentName');
  if (chatAgentName) chatAgentName.textContent = t('chat.agent');
  const chatInput = document.getElementById('chatInput');
  if (chatInput) chatInput.placeholder = t('chat.placeholder');
  const chatGreeting = document.getElementById('chatGreeting');
  if (chatGreeting) chatGreeting.innerHTML = t('chat.greeting');
  // Quick reply buttons
  const qbtnTarifs = document.getElementById('qbtnTarifs');
  if (qbtnTarifs) qbtnTarifs.textContent = t('chat.q.tarifs');
  const qbtnInscription = document.getElementById('qbtnInscription');
  if (qbtnInscription) qbtnInscription.textContent = t('chat.q.inscription');
  const qbtnContact = document.getElementById('qbtnContact');
  if (qbtnContact) qbtnContact.textContent = t('chat.q.contact');

  // --- COOKIE BANNER ---
  const cookieBanner = document.getElementById('cookieBanner');
  if (cookieBanner) {
    const cookieP = cookieBanner.querySelector('p');
    if (cookieP) cookieP.innerHTML = `${t('cookie.text')} <a href="pages/confidentialite.html">${t('cookie.learn')}</a>`;
    const cookieAccept = cookieBanner.querySelector('.btn-cookie-accept');
    if (cookieAccept) cookieAccept.textContent = t('cookie.accept');
    const cookieDecline = cookieBanner.querySelector('.btn-cookie-decline');
    if (cookieDecline) cookieDecline.textContent = t('cookie.decline');
  }

  // --- POPUP DE BIENVENUE ---
  const popupBadge = document.querySelector('.welcome-header .offer-badge');
  if (popupBadge) popupBadge.textContent = t('popup.badge');
  const popupH2 = document.querySelector('.welcome-header h2');
  if (popupH2) popupH2.innerHTML = t('popup.h2');
  const popupP = document.querySelector('.welcome-header p');
  if (popupP) popupP.textContent = t('popup.p');
  const popupPerks = document.querySelectorAll('.welcome-perks li');
  const perkKeys = ['popup.perk1','popup.perk2','popup.perk3','popup.perk4'];
  popupPerks.forEach((li, i) => { if (perkKeys[i]) li.innerHTML = t(perkKeys[i]); });
  const popupBtn = document.querySelector('.welcome-body .btn-primary');
  if (popupBtn) popupBtn.textContent = t('popup.btn');
  const popupOr = document.getElementById('popupOr');
  if (popupOr) popupOr.textContent = t('popup.or');
  const popupLink = document.querySelector('.welcome-body .popup-or-link');
  if (popupLink) popupLink.textContent = t('popup.link');

  // --- ONGLETS MODAL AUTH ---
  const tabLogin = document.getElementById('tabLogin');
  if (tabLogin) tabLogin.textContent = t('auth.tab.login');
  const tabRegister = document.getElementById('tabRegister');
  if (tabRegister) tabRegister.textContent = t('auth.tab.register');

  // --- BOUTON RETOUR EN HAUT ---
  const scrollTopBtn = document.querySelector('.scroll-top');
  if (scrollTopBtn) scrollTopBtn.title = L === 'en' ? 'Back to top' : 'Retour en haut';

  // --- BULLE WHATSAPP ---
  const waTooltipStrong = document.querySelector('.wa-tooltip strong');
  if (waTooltipStrong) waTooltipStrong.textContent = L === 'en' ? 'Need help? 💬' : 'Besoin d\'aide ? 💬';
  const waTooltipP = document.querySelector('.wa-tooltip p');
  if (waTooltipP) waTooltipP.textContent = L === 'en'
    ? 'Chat with us on WhatsApp — fast response!'
    : 'Posez vos questions sur WhatsApp — réponse rapide !';

  // --- TITRE DE PAGE ---
  if (L === 'en') {
    if (!document.title.includes('Training Center –') || document.title.includes('Préparation')) {
      const base = document.title.replace('Préparation TEF & TCF Canada', 'TEF & TCF Canada Preparation');
      document.title = base;
    }
  } else {
    const base = document.title.replace('TEF & TCF Canada Preparation', 'Préparation TEF & TCF Canada');
    document.title = base;
  }
}

function switchLang() {
  currentLang = currentLang === 'fr' ? 'en' : 'fr';
  localStorage.setItem('arc_lang', currentLang);
  applyTranslations();
}

// Lancement au chargement
document.addEventListener('DOMContentLoaded', applyTranslations);

